mapper.sql:
l.deleted_at IS NULL

  AND (
    l.name LIKE CONCAT('%', #{keyword}, '%')
    OR EXISTS (
      SELECT 1
      FROM group_link_import_batch b
      WHERE b.label_id = l.id
        AND b.deleted_at IS NULL
        AND (
          b.source_file_name LIKE CONCAT('%', #{keyword}, '%')
          OR b.batch_name LIKE CONCAT('%', #{keyword}, '%')
          OR CAST(b.id AS CHAR) = #{keyword}
        )
    )
  )

AND l.id = #{id}
AND l.created_at >= #{createdFrom}
AND l.created_at <= #{createdTo}

mapper.update:
UPDATE group_link_label
SET name = #{name}, region = #{region}, remark = #{remark}, updated_at = #{updatedAt}
WHERE id = #{id} AND deleted_at IS NULL

UPDATE group_link_label SET deleted_at = #{deletedAt}
WHERE deleted_at IS NULL AND id IN
#{i}
